        public MainWindow()
        {
            InitializeComponent();
            _appDarkModeEnabled = AccessibilityPreferences.DarkModeEnabled;
            ProgrammingLanguageInput.ItemsSource = KnownProgrammingLanguages.OrderBy(language => language).ToList();
            InitializeTeamsUi();
            InitializeRealtimeSync();
            ApplyAppTheme();
            SyncThemeToggleState();
            ApplySidebarState();
            SetActiveNavigation("Chats");
            this.KeyDown += MainWindow_KeyDown;
            this.Loaded += MainWindow_Loaded;
        }

        private void SyncThemeToggleState()
        {
            if (ChatDarkModeToggle != null)
            {
                ChatDarkModeToggle.IsChecked = _appDarkModeEnabled;
            }
        }

        private T FindRequiredTitleBarElement<T>(string tag) where T : FrameworkElement
        {
            var element = MainWindowTitleBar?.FindTaggedContentElement<T>(tag);
            if (element != null)
            {
                return element;
            }

            throw new InvalidOperationException($"Elemento da title bar não encontrado: {tag}");
        }

        private async void MainWindow_Loaded(object sender, RoutedEventArgs e)
        {
            DebugHelper.WriteLine("MainWindow carregada");
            DebugConsoleManager.EnsureVisible(this);

            if (!string.IsNullOrWhiteSpace(_idToken) && _currentProfile != null)
            {
                _teamService = new TeamService(_idToken, _currentProfile.UserId ?? "", TeamPermissionService.NormalizeRole(_currentProfile.Role));
                _teachingClassService = new TeachingClassService(_idToken, _currentProfile.UserId ?? "", TeamPermissionService.NormalizeRole(_currentProfile.Role));
                _connectionService = new ConnectionService(_idToken, _currentProfile);

                RenderChatsLoadingState();
                await Dispatcher.Yield(DispatcherPriority.Background);

                await LoadActiveConversationsAsync();
                _ = LoadTeamsFromDatabaseAsync(force: true);
                _ = LoadTeachingClassesFromDatabaseAsync(force: true);
                _ = RefreshConnectionsCacheAsync();
                _realtimeSyncTimer.Start();
            }
            else
            {
                RefreshChatsUI();
                UpdateConnectionsBadge();
                _realtimeSyncTimer.Stop();
            }
        }

        private void InitializeRealtimeSync()
        {
            _realtimeSyncTimer.Interval = TimeSpan.FromSeconds(45);
            _realtimeSyncTimer.Tick += RealtimeSyncTimer_Tick;
        }

        private async void RealtimeSyncTimer_Tick(object? sender, EventArgs e)
        {
            if (_realtimeSyncInFlight || string.IsNullOrWhiteSpace(_idToken) || _currentProfile == null)
            {
                return;
            }

            _realtimeSyncInFlight = true;
            try
            {
                await LoadActiveConversationsAsync();
                await LoadTeamsFromDatabaseAsync();
                await LoadTeachingClassesFromDatabaseAsync();
                await RefreshConnectionsCacheAsync();
            }
            catch (Exception ex)
            {
                DebugHelper.WriteLine($"[RealtimeSync] Falha durante sincronizacao: {ex.Message}");
            }
            finally
            {
                _realtimeSyncInFlight = false;
            }
        }

        private void MainWindow_KeyDown(object sender, KeyEventArgs e)
        {
            if (e.Key == Key.Escape && SearchSlidePanel.Visibility == Visibility.Visible)
            {
                HideSearchSlidePanel();
                e.Handled = true;
                return;
            }

            if (e.Key == Key.D && Keyboard.Modifiers == (ModifierKeys.Control | ModifierKeys.Shift))
            {
                DebugConsoleManager.Toggle(this);
                e.Handled = true;
                return;
            }

            if (e.Key == Key.D && Keyboard.Modifiers == ModifierKeys.Control)
            {
                if (!DebugHelper.IsInitialized)
                {
                    DebugHelper.Initialize();
                }
                else
                {
                    DebugHelper.OpenLogFile();
                }
                e.Handled = true;
            }
        }

