                            Foreground = GetThemeBrush("PrimaryTextBrush")
                        },
                        new Border
                        {
                            Margin = new Thickness(0, 10, 0, 8),
                            Child = metaWrap
                        },
                        itemStack
                    }
                }
            };
        }

