            var removeButton = CreateFilesHubActionButton("Remover", GetThemeBrush("MutedCardBackgroundBrush"), GetThemeBrush("PrimaryTextBrush"), GetThemeBrush("CardBorderBrush"), RemoveFilesHubItem_Click, item, 104);
