        private Border CreateCalendarFilterSelector(string label, IEnumerable<(string Label, string Value)> options, string selectedValue, Action<string> onChanged)
        {
            var container = new Border
            {
                Background = GetThemeBrush("MutedCardBackgroundBrush"),
                BorderBrush = GetThemeBrush("CardBorderBrush"),
                BorderThickness = new Thickness(1),
                CornerRadius = new CornerRadius(16),
                Padding = new Thickness(12),
                Margin = new Thickness(0, 0, 10, 10),
                MinWidth = 188
            };

            var stack = new StackPanel();
            stack.Children.Add(new TextBlock
            {
                Text = label,
                FontSize = 10,
                FontWeight = FontWeights.Bold,
                Foreground = GetThemeBrush("SecondaryTextBrush")
            });

            var combo = new ComboBox
            {
                Height = 40,
                Margin = new Thickness(0, 8, 0, 0),
                DisplayMemberPath = nameof(DialogSelectionOption.Label),
                SelectedValuePath = nameof(DialogSelectionOption.Value),
                ItemsSource = options.Select(item => new DialogSelectionOption { Label = item.Label, Value = item.Value }).ToList(),
                SelectedValue = selectedValue
            };
            ApplyDialogInputStyle(combo);
            combo.SelectionChanged += (s, e) =>
            {
                if (combo.SelectedValue is string value)
                {
                    onChanged(value);
                }
            };

            stack.Children.Add(combo);
            container.Child = stack;
            return container;
        }

        private Button CreateCalendarMonthNavigationButton(PackIconMaterialKind iconKind, string tooltip, Action onClick, bool filled = false)
