                            new TextBlock
                            {
                                Text = notification.CreatedAt.ToString("dd/MM HH:mm"),
                                FontSize = 10,
                                Margin = new Thickness(0, 6, 0, 0),
                                Foreground = GetThemeBrush("TertiaryTextBrush")
                            }
                        }
                    }
                });
            }

            return border;
        }

