            footer.ColumnDefinitions.Add(new ColumnDefinition { Width = GridLength.Auto });
            footer.ColumnDefinitions.Add(new ColumnDefinition { Width = GridLength.Auto });

            var footerHint = new TextBlock
            {
                Text = "Preparando opções do personagem...",
                VerticalAlignment = VerticalAlignment.Center,
