                FontSize = 12.5,
                FontWeight = FontWeights.SemiBold,
                Foreground = GetThemeBrush("PrimaryTextBrush")
            });

            TeachingClassPostCommentInfo? replyTarget = null;
            var replyBanner = new Border
            {
