            form.Children.Add(CreateDialogSectionCard(
                "Sinalização do projeto",
                "Esses campos ajudam a deixar o quadro mais legível para toda a equipe.",
                accentBrush,
                planningContent,
                new Thickness(0, 0, 0, 8)));

