            {
                Content = "Conversar",
                Background = GetThemeBrush("AccentBrush"),
                Foreground = Brushes.White,
                BorderThickness = new Thickness(0),
                Padding = new Thickness(14, 8, 14, 8),
                Margin = new Thickness(0, 0, 0, 8),
                Cursor = Cursors.Hand,
                FontWeight = FontWeights.SemiBold,
                Tag = user
            };
