                        ? "1 equipe/projeto visível para supervisão"
                        : $"{teams.Count} equipes/projetos visíveis para supervisão",
                FontSize = 11,
                FontWeight = FontWeights.SemiBold,
                Foreground = GetThemeBrush("PrimaryTextBrush")
            });

            if (teams.Count == 0)
            {
