                            {
                                new Border
                                {
                                    Width = 86,
                                    Height = 86,
                                    CornerRadius = new CornerRadius(43),
                                    Background = new SolidColorBrush(Color.FromRgb(0, 168, 132)),
                                    HorizontalAlignment = HorizontalAlignment.Center,
                                    Child = new TextBlock
                                    {
                                        Text = "Chat",
                                        Foreground = Brushes.White,
                                        FontSize = 20,
                                        FontWeight = FontWeights.Bold,
                                        HorizontalAlignment = HorizontalAlignment.Center,
                                        VerticalAlignment = VerticalAlignment.Center
                                    }
                                },
                                new TextBlock
                                {
                                    Text = "Selecione uma conversa para abrir o painel principal",
                                    FontSize = 22,
                                    FontWeight = FontWeights.ExtraBold,
                                    Foreground = primaryText,
                                    Margin = new Thickness(0, 22, 0, 10),
                                    TextAlignment = TextAlignment.Center,
                                    TextWrapping = TextWrapping.Wrap
                                },
                                new TextBlock
                                {
                                    Text = "A lista de conversas fica sempre visível na esquerda, com Favoritos, Chats e seu chat próprio já prontos para uso.",
                                    FontSize = 13,
                                    Foreground = secondaryText,
                                    TextAlignment = TextAlignment.Center,
                                    TextWrapping = TextWrapping.Wrap,
                                    Margin = new Thickness(0, 0, 0, 24)
                                },
                                new Border
                                {
                                    Background = mutedBackground,
                                    BorderBrush = headerBorderBrush,
                                    BorderThickness = new Thickness(1),
                                    CornerRadius = new CornerRadius(18),
                                    Padding = new Thickness(18),
                                    Child = new TextBlock
                                    {
                                        Text = "Use a busca do topo para iniciar novas conversas ou abra o chat próprio para guardar notas, lembretes e arquivos rápidos.",
                                        FontSize = 12,
                                        Foreground = secondaryText,
                                        TextWrapping = TextWrapping.Wrap,
                                        TextAlignment = TextAlignment.Center
                                    }
                                }
                            }
                        }
                    }
                }
            };

            return panel;
        }

        private Border CreateChatWorkspace(Conversation conv)
        {
            var panelBackground = _appDarkModeEnabled
                ? new SolidColorBrush(Color.FromRgb(17, 27, 33))
                : new SolidColorBrush(Colors.White);
            var borderBrush = _appDarkModeEnabled
                ? new SolidColorBrush(Color.FromRgb(32, 44, 51))
                : new SolidColorBrush(Color.FromRgb(226, 232, 240));
            var primaryText = _appDarkModeEnabled
                ? new SolidColorBrush(Color.FromRgb(233, 237, 239))
                : new SolidColorBrush(Color.FromRgb(15, 23, 42));
            var secondaryText = _appDarkModeEnabled
                ? new SolidColorBrush(Color.FromRgb(134, 150, 160))
                : new SolidColorBrush(Color.FromRgb(100, 116, 139));
            var canvasBackground = _appDarkModeEnabled
                ? new SolidColorBrush(Color.FromRgb(12, 19, 24))
                : new SolidColorBrush(Color.FromRgb(248, 250, 252));
            var composerBackground = _appDarkModeEnabled
                ? new SolidColorBrush(Color.FromRgb(17, 27, 33))
                : new SolidColorBrush(Color.FromRgb(255, 255, 255));
            var inputBackground = _appDarkModeEnabled
                ? new SolidColorBrush(Color.FromRgb(47, 61, 69))
                : new SolidColorBrush(Color.FromRgb(241, 245, 249));
            var inputForeground = _appDarkModeEnabled
                ? new SolidColorBrush(Color.FromRgb(233, 237, 239))
                : new SolidColorBrush(Color.FromRgb(15, 23, 42));

            var panel = new Border
            {
                Background = panelBackground,
                BorderBrush = borderBrush,
                BorderThickness = new Thickness(1),
                CornerRadius = new CornerRadius(24)
            };

            var mainGrid = new Grid();
            mainGrid.RowDefinitions.Add(new RowDefinition { Height = GridLength.Auto });
            mainGrid.RowDefinitions.Add(new RowDefinition { Height = GridLength.Auto });
            mainGrid.RowDefinitions.Add(new RowDefinition { Height = new GridLength(1, GridUnitType.Star) });
            mainGrid.RowDefinitions.Add(new RowDefinition { Height = GridLength.Auto });

            var headerBorder = new Border
            {
                BorderBrush = borderBrush,
                BorderThickness = new Thickness(0, 0, 0, 1),
                Padding = new Thickness(18, 16, 18, 16)
            };

            var headerGrid = new Grid();
            headerGrid.ColumnDefinitions.Add(new ColumnDefinition { Width = GridLength.Auto });
            headerGrid.ColumnDefinitions.Add(new ColumnDefinition { Width = new GridLength(1, GridUnitType.Star) });
            headerGrid.ColumnDefinitions.Add(new ColumnDefinition { Width = GridLength.Auto });

            var avatarGrid = new Grid
            {
                Width = 46,
                Height = 46,
                Margin = new Thickness(0, 0, 14, 0)
            };
            avatarGrid.Children.Add(CreateConversationAvatarVisual(conv, 46));
            Grid.SetColumn(avatarGrid, 0);
            headerGrid.Children.Add(avatarGrid);

            var titleStack = new StackPanel
            {
                Orientation = Orientation.Vertical,
                VerticalAlignment = VerticalAlignment.Center
            };
            titleStack.Children.Add(new TextBlock
            {
                Text = conv.IsSelfConversation ? "Você" : conv.ContactName,
                FontSize = 15,
                FontWeight = FontWeights.SemiBold,
                Foreground = primaryText
            });
            titleStack.Children.Add(new TextBlock
            {
                Text = GetConversationWorkspaceSubtitle(conv),
                FontSize = 11,
                Margin = new Thickness(0, 3, 0, 0),
                Foreground = secondaryText
            });
            Grid.SetColumn(titleStack, 1);
            headerGrid.Children.Add(titleStack);

            var actionPanel = new StackPanel
            {
                Orientation = Orientation.Horizontal,
                HorizontalAlignment = HorizontalAlignment.Right,
                VerticalAlignment = VerticalAlignment.Center
            };

            if (!conv.IsSelfConversation)
            {
                var audioCallButton = CreateHeaderIconButton(PackIconMaterialKind.PhoneOutline, "Solicitar audio", new SolidColorBrush(Color.FromRgb(14, 165, 233)));
                audioCallButton.Click += async (_, __) => await RequestConversationCallAsync(conv, "audio");
                actionPanel.Children.Add(audioCallButton);

                var videoCallButton = CreateHeaderIconButton(PackIconMaterialKind.VideoOutline, "Solicitar video", new SolidColorBrush(Color.FromRgb(236, 72, 153)));
                videoCallButton.Click += async (_, __) => await RequestConversationCallAsync(conv, "video");
                actionPanel.Children.Add(videoCallButton);
            }

            var searchButton = CreateHeaderIconButton(PackIconMaterialKind.Magnify, "Buscar na conversa", new SolidColorBrush(Color.FromRgb(99, 102, 241)));
            searchButton.Click += (_, __) => ShowConversationSearchDialog(conv);
            actionPanel.Children.Add(searchButton);

            var menuButton = CreateHeaderIconButton(PackIconMaterialKind.DotsHorizontal, "Mais acoes");
            var actionsPopup = CreateChatActionsPopup(menuButton, conv);
            menuButton.Click += (s, e) => actionsPopup.IsOpen = !actionsPopup.IsOpen;
            actionPanel.Children.Add(menuButton);

            Grid.SetColumn(actionPanel, 2);
            headerGrid.Children.Add(actionPanel);

            headerBorder.Child = headerGrid;
            mainGrid.Children.Add(headerBorder);
            Grid.SetRow(headerBorder, 0);

            TextBox? inputBox = null;

            var quickToolsBorder = new Border
            {
                Background = _appDarkModeEnabled
                    ? new SolidColorBrush(Color.FromRgb(15, 23, 42))
                    : new SolidColorBrush(Color.FromRgb(248, 250, 252)),
                BorderBrush = borderBrush,
                BorderThickness = new Thickness(0, 0, 0, 1),
                Padding = new Thickness(18, 12, 18, 12)
            };

            var quickTools = new WrapPanel();
            if (conv.IsSelfConversation)
            {
                var notesButton = CreateComposerChipButton("Notas", PackIconMaterialKind.NoteTextOutline, new SolidColorBrush(Color.FromRgb(59, 130, 246)));
                notesButton.Click += (_, __) => PrefillChatComposer(inputBox, "Nota:\n- ");
                quickTools.Children.Add(notesButton);

                var mediaButton = CreateComposerChipButton("Mídia", PackIconMaterialKind.ImageOutline, new SolidColorBrush(Color.FromRgb(14, 165, 233)));
                mediaButton.Click += async (_, __) => await HandleConversationMediaSelectionAsync(conv, inputBox, "Selecionar midia para o chat", "Midia|*.png;*.jpg;*.jpeg;*.gif;*.webp;*.bmp;*.mp4;*.mov;*.avi;*.wmv|Todos os arquivos|*.*");
                quickTools.Children.Add(mediaButton);

                var filesButton = CreateComposerChipButton("Arquivos", PackIconMaterialKind.FolderOutline, new SolidColorBrush(Color.FromRgb(16, 185, 129)));
                filesButton.Click += async (_, __) => await SendConversationAttachmentsAsync(conv, inputBox, "Selecionar arquivos para o chat", "Todos os arquivos|*.*");
                quickTools.Children.Add(filesButton);

                var reminderButton = CreateComposerChipButton("Lembretes", PackIconMaterialKind.BellOutline, new SolidColorBrush(Color.FromRgb(245, 158, 11)));
                reminderButton.Click += (_, __) => PrefillChatComposer(inputBox, "Lembrete:\n- ");
                quickTools.Children.Add(reminderButton);
            }
            else
            {
                var filesButton = CreateComposerChipButton("Arquivos", PackIconMaterialKind.FolderOutline, new SolidColorBrush(Color.FromRgb(59, 130, 246)));
                filesButton.Click += async (_, __) => await SendConversationAttachmentsAsync(conv, inputBox, "Selecionar arquivos para compartilhar no chat", "Todos os arquivos|*.*");
                quickTools.Children.Add(filesButton);

                var mediaButton = CreateComposerChipButton("Mídia", PackIconMaterialKind.ImageOutline, new SolidColorBrush(Color.FromRgb(14, 165, 233)));
                mediaButton.Click += async (_, __) => await HandleConversationMediaSelectionAsync(conv, inputBox, "Selecionar midia para compartilhar no chat", "Midia|*.png;*.jpg;*.jpeg;*.gif;*.webp;*.bmp;*.mp4;*.mov;*.avi;*.wmv|Todos os arquivos|*.*");
                quickTools.Children.Add(mediaButton);

                var mentionButton = CreateComposerChipButton("@Professor", PackIconMaterialKind.SchoolOutline, new SolidColorBrush(Color.FromRgb(124, 58, 237)));
                mentionButton.Click += (_, __) => PrefillChatComposer(inputBox, "@Professor preciso de orientacao sobre: ");
                quickTools.Children.Add(mentionButton);

                var exportButton = CreateComposerChipButton("Exportar", PackIconMaterialKind.ExportVariant, new SolidColorBrush(Color.FromRgb(16, 185, 129)));
                exportButton.Click += (_, __) => ExportConversationHistory(conv);
                quickTools.Children.Add(exportButton);
            }

            quickToolsBorder.Child = quickTools;
            mainGrid.Children.Add(quickToolsBorder);
            Grid.SetRow(quickToolsBorder, 1);

            var messagesHost = new Border
            {
                Background = canvasBackground
            };

            if (conv.Messages.Count == 0)
            {
                var emptyState = new StackPanel
                {
                    Width = 360,
                    HorizontalAlignment = HorizontalAlignment.Center,
                    VerticalAlignment = VerticalAlignment.Center
                };

                if (conv.IsSelfConversation)
                {
                    emptyState.Children.Add(new Image
                    {
                        Source = new BitmapImage(new Uri("pack://application:,,,/img/Chat/CheeseOwnChatTransparent.png", UriKind.Absolute)),
                        Width = 240,
                        Height = 340,
                        Stretch = Stretch.Uniform,
                        HorizontalAlignment = HorizontalAlignment.Center,
                        Margin = new Thickness(0, 0, 0, 8)
                    });
                }

                emptyState.Children.Add(new TextBlock
                {
                    Text = conv.IsSelfConversation ? "Seu chat próprio está pronto" : "Nenhuma mensagem por aqui ainda",
                    FontSize = 20,
                    FontWeight = FontWeights.Bold,
                    Foreground = primaryText,
                    TextAlignment = TextAlignment.Center
                });
                emptyState.Children.Add(new TextBlock
                {
                    Text = conv.IsSelfConversation ? SelfChatPlaceholderText : "Envie a primeira mensagem e mantenha a conversa aberta enquanto acessa as ações principais acima.",
                    FontSize = 12,
                    Margin = new Thickness(0, 10, 0, 0),
                    Foreground = secondaryText,
                    TextWrapping = TextWrapping.Wrap,
                    TextAlignment = TextAlignment.Center
                });

                messagesHost.Child = emptyState;
            }
            else
            {
                var messagesList = new StackPanel { Orientation = Orientation.Vertical };
                var renderedMediaGroupIds = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
                foreach (var msg in conv.Messages.OrderBy(message => message.Timestamp))
                {
                    if (msg.IsMediaGroupItem && !renderedMediaGroupIds.Add(msg.MediaGroupId))
                    {
                        continue;
                    }

                    messagesList.Children.Add(CreateMessageBubble(conv, msg));
                }

                var scrollViewer = new ScrollViewer
                {
                    VerticalScrollBarVisibility = ScrollBarVisibility.Auto,
                    Content = messagesList,
                    Padding = new Thickness(18, 20, 18, 20),
                    Background = canvasBackground
                };
                scrollViewer.Loaded += (s, e) => scrollViewer.ScrollToEnd();
                messagesHost.Child = scrollViewer;
            }

            mainGrid.Children.Add(messagesHost);
            Grid.SetRow(messagesHost, 2);

            var inputBorder = new Border
            {
                Background = composerBackground,
                BorderBrush = borderBrush,
                BorderThickness = new Thickness(0, 1, 0, 0),
                Padding = new Thickness(16, 14, 16, 16)
            };

            var composerStack = new StackPanel();
            var quickActionPanel = new WrapPanel
            {
                Margin = new Thickness(0, 0, 0, 12)
            };
            if (conv.IsSelfConversation)
            {
                var notesShortcutButton = CreateComposerChipButton("Notas", PackIconMaterialKind.NoteTextOutline, new SolidColorBrush(Color.FromRgb(245, 158, 11)));
                notesShortcutButton.Click += (_, __) => PrefillChatComposer(inputBox, "Nota:\n- ");
                quickActionPanel.Children.Add(notesShortcutButton);

                var mediaShortcutButton = CreateComposerChipButton("Mídia", PackIconMaterialKind.ImageOutline, new SolidColorBrush(Color.FromRgb(14, 165, 233)));
                mediaShortcutButton.Click += async (_, __) => await HandleConversationMediaSelectionAsync(conv, inputBox, "Selecionar midia para o chat", "Midia|*.png;*.jpg;*.jpeg;*.gif;*.webp;*.bmp;*.mp4;*.mov;*.avi;*.wmv|Todos os arquivos|*.*");
                quickActionPanel.Children.Add(mediaShortcutButton);

                var fileShortcutButton = CreateComposerChipButton("Arquivo", PackIconMaterialKind.Paperclip, new SolidColorBrush(Color.FromRgb(59, 130, 246)));
                fileShortcutButton.Click += async (_, __) => await SendConversationAttachmentsAsync(conv, inputBox, "Selecionar arquivos para o chat", "Todos os arquivos|*.*");
                quickActionPanel.Children.Add(fileShortcutButton);

                var checklistButton = CreateComposerChipButton("Checklist", PackIconMaterialKind.FormatListChecks, new SolidColorBrush(Color.FromRgb(124, 58, 237)));
                checklistButton.Click += (_, __) => PrefillChatComposer(inputBox, "Checklist:\n- ");
                quickActionPanel.Children.Add(checklistButton);

                var reminderShortcutButton = CreateComposerChipButton("Lembrete", PackIconMaterialKind.BellOutline, new SolidColorBrush(Color.FromRgb(16, 185, 129)));
                reminderShortcutButton.Click += (_, __) => PrefillChatComposer(inputBox, "Lembrete:\n- ");
                quickActionPanel.Children.Add(reminderShortcutButton);
            }
            else
            {
                var quickActionButton = CreateComposerChipButton("Ações rápidas", PackIconMaterialKind.AutoFix, new SolidColorBrush(Color.FromRgb(245, 158, 11)));
                quickActionButton.Click += (_, __) => PrefillChatComposer(inputBox, "Proximo passo:\n- ");
                quickActionPanel.Children.Add(quickActionButton);

                var mediaShortcutButton = CreateComposerChipButton("Mídia", PackIconMaterialKind.ImageOutline, new SolidColorBrush(Color.FromRgb(14, 165, 233)));
                mediaShortcutButton.Click += async (_, __) => await HandleConversationMediaSelectionAsync(conv, inputBox, "Selecionar midia para compartilhar no chat", "Midia|*.png;*.jpg;*.jpeg;*.gif;*.webp;*.bmp;*.mp4;*.mov;*.avi;*.wmv|Todos os arquivos|*.*");
                quickActionPanel.Children.Add(mediaShortcutButton);

                var fileShortcutButton = CreateComposerChipButton("Arquivo", PackIconMaterialKind.Paperclip, new SolidColorBrush(Color.FromRgb(59, 130, 246)));
                fileShortcutButton.Click += async (_, __) => await SendConversationAttachmentsAsync(conv, inputBox, "Selecionar arquivos para compartilhar no chat", "Todos os arquivos|*.*");
                quickActionPanel.Children.Add(fileShortcutButton);

                var professorShortcutButton = CreateComposerChipButton("Professor", PackIconMaterialKind.SchoolOutline, new SolidColorBrush(Color.FromRgb(124, 58, 237)));
                professorShortcutButton.Click += (_, __) => PrefillChatComposer(inputBox, "@Professor preciso de orientacao sobre: ");
                quickActionPanel.Children.Add(professorShortcutButton);

                var exportShortcutButton = CreateComposerChipButton("Exportar", PackIconMaterialKind.ExportVariant, new SolidColorBrush(Color.FromRgb(16, 185, 129)));
                exportShortcutButton.Click += (_, __) => ExportConversationHistory(conv);
                quickActionPanel.Children.Add(exportShortcutButton);
            }
            composerStack.Children.Add(quickActionPanel);

            var inputGrid = new Grid();
            inputGrid.ColumnDefinitions.Add(new ColumnDefinition { Width = GridLength.Auto });
            inputGrid.ColumnDefinitions.Add(new ColumnDefinition { Width = GridLength.Auto });
            inputGrid.ColumnDefinitions.Add(new ColumnDefinition { Width = new GridLength(1, GridUnitType.Star) });
            inputGrid.ColumnDefinitions.Add(new ColumnDefinition { Width = GridLength.Auto });
            inputGrid.ColumnDefinitions.Add(new ColumnDefinition { Width = GridLength.Auto });

            var emojiButton = CreateHeaderIconButton(PackIconMaterialKind.EmoticonHappyOutline, "Emoji", new SolidColorBrush(Color.FromRgb(245, 158, 11)));
            var attachmentButton = CreateHeaderIconButton(PackIconMaterialKind.StickerOutline, "Enviar figurinha", new SolidColorBrush(Color.FromRgb(236, 72, 153)));
            attachmentButton.Background = new SolidColorBrush(Color.FromRgb(0, 168, 132));
            attachmentButton.Foreground = Brushes.White;
            attachmentButton.MinWidth = 40;
            attachmentButton.Height = 40;
            attachmentButton.FontSize = 16;

            inputBox = new TextBox
            {
                Background = inputBackground,
                Foreground = inputForeground,
                BorderBrush = inputBackground,
                BorderThickness = new Thickness(1),
                Padding = new Thickness(14, 12, 14, 12),
                FontSize = 13,
                MinHeight = 48,
                VerticalAlignment = VerticalAlignment.Center,
                Margin = new Thickness(10, 0, 10, 0),
                TextWrapping = TextWrapping.Wrap,
                AcceptsReturn = true,
                MaxHeight = 100
            };
            inputBox.KeyDown += async (s, e) =>
            {
                if (e.Key == Key.Enter && Keyboard.Modifiers != ModifierKeys.Shift)
                {
                    e.Handled = true;
                    await SendConversationMessageAsync(conv, inputBox);
                }
            };

            var emojiPopup = CreateEmojiPickerPopup(emojiButton, inputBox);
            emojiButton.Click += (s, e) => emojiPopup.IsOpen = !emojiPopup.IsOpen;
            Grid.SetColumn(emojiButton, 0);
            inputGrid.Children.Add(emojiButton);

            var stickerPopup = CreateStickerPickerPopup(attachmentButton, conv);
            attachmentButton.Click += (s, e) => stickerPopup.IsOpen = !stickerPopup.IsOpen;
            Grid.SetColumn(attachmentButton, 1);
            inputGrid.Children.Add(attachmentButton);

            Grid.SetColumn(inputBox, 2);
            inputGrid.Children.Add(inputBox);

            var micButton = CreateHeaderIconButton(PackIconMaterialKind.MicrophoneOutline, "Gravar audio", new SolidColorBrush(Color.FromRgb(20, 184, 166)));
            micButton.Click += async (_, __) => await RecordConversationAudioAsync(conv, inputBox);
            Grid.SetColumn(micButton, 3);
            inputGrid.Children.Add(micButton);

            var sendButton = new Button
            {
                Content = "➤",
                Background = new SolidColorBrush(Color.FromRgb(0, 168, 132)),
                Foreground = Brushes.White,
                FontSize = 16,
                Width = 52,
                Height = 42,
                BorderThickness = new Thickness(0),
                Cursor = Cursors.Hand,
                FontWeight = FontWeights.SemiBold,
                VerticalAlignment = VerticalAlignment.Center,
                ToolTip = "Enviar mensagem"
            };
            sendButton.Click += async (s, e) => await SendConversationMessageAsync(conv, inputBox);
            Grid.SetColumn(sendButton, 4);
            inputGrid.Children.Add(sendButton);

            composerStack.Children.Add(inputGrid);
            inputBorder.Child = composerStack;
            mainGrid.Children.Add(inputBorder);
            Grid.SetRow(inputBorder, 3);

            panel.Child = mainGrid;
            return panel;
        }

        private async Task SendConversationStickerAsync(Conversation conv, string stickerAsset)
        {
            if (string.IsNullOrWhiteSpace(stickerAsset))
            {
                return;
            }

            var previewText = GetStickerPreviewText(stickerAsset);
            var stickerMessage = new ChatMessage
            {
                SenderId = _currentProfile?.UserId ?? "self",
                SenderName = _currentProfile?.Name ?? "Voce",
                Content = previewText,
                MessageType = "sticker",
                StickerAsset = stickerAsset,
                Timestamp = DateTime.Now,
                IsOwn = true
            };

            ChatMessage messageToAppend = stickerMessage;

            if (!string.IsNullOrEmpty(_idToken))
            {
                var chatService = new ChatService(_idToken, _currentProfile?.UserId ?? "");
                var sendResult = await chatService.SendMessageAsync(conv.ContactId, conv.ContactName, stickerMessage.SenderName, stickerMessage.Content, stickerMessage.MessageType, stickerMessage.StickerAsset);
                if (!sendResult.Success)
                {
                    MessageBox.Show(
                        $"Erro ao enviar figurinha.\n\n{sendResult.ErrorMessage}\n\nLog salvo em:\n{DebugHelper.GetLogFilePath()}",
                        "Erro",
                        MessageBoxButton.OK,
                        MessageBoxImage.Warning
                    );
                    return;
                }

                messageToAppend = NormalizeChatMessageForUi(sendResult.Message ?? stickerMessage);
            }

            AppendMessagesToConversation(conv, messageToAppend);
        }

        private async Task SendConversationMessageAsync(Conversation conv, TextBox inputBox)
        {
            var messageText = inputBox.Text?.Trim() ?? string.Empty;
            if (string.IsNullOrWhiteSpace(messageText))
            {
                return;
            }

            if (await SendConversationTextAsync(conv, messageText))
            {
                inputBox.Clear();
            }
        }

        private async Task<bool> SendConversationTextAsync(Conversation conv, string messageText)
        {
            var normalizedMessage = (messageText ?? string.Empty).Trim();
            if (string.IsNullOrWhiteSpace(normalizedMessage))
            {
                return false;
            }

            var newMsg = new ChatMessage
            {
                SenderId = _currentProfile?.UserId ?? "self",
                SenderName = _currentProfile?.Name ?? "Voce",
                Content = normalizedMessage,
                MessageType = "text",
                Timestamp = DateTime.Now,
                IsOwn = true
            };

            ChatMessage messageToAppend = newMsg;

            if (!string.IsNullOrEmpty(_idToken))
            {
                DebugHelper.WriteLine("[SendConversationMessageAsync] Enviando mensagem para Firebase");
                var chatService = new ChatService(_idToken, _currentProfile?.UserId ?? "");
                var sendResult = await chatService.SendMessageAsync(conv.ContactId, conv.ContactName, newMsg.SenderName, newMsg.Content, newMsg.MessageType, newMsg.StickerAsset);

                if (!sendResult.Success)
                {
                    MessageBox.Show(
                        $"Erro ao enviar mensagem.\n\n{sendResult.ErrorMessage}\n\nLog salvo em:\n{DebugHelper.GetLogFilePath()}",
                        "Erro",
                        MessageBoxButton.OK,
                        MessageBoxImage.Warning
                    );
                    DebugHelper.WriteLine($"[SendConversationMessageAsync] Falha ao salvar no Firebase: {sendResult.ErrorMessage}");
                    return false;
                }

                messageToAppend = NormalizeChatMessageForUi(sendResult.Message ?? newMsg);
                DebugHelper.WriteLine("[SendConversationMessageAsync] Mensagem salva no Firebase");
            }

            AppendMessagesToConversation(conv, messageToAppend);
            return true;
        }

        private async Task SendConversationAttachmentsAsync(Conversation conv, TextBox? inputBox, string title, string filter)
        {
            var dialog = new OpenFileDialog
            {
                Multiselect = true,
                Title = title,
                Filter = filter
            };

            if (dialog.ShowDialog() != true || dialog.FileNames.Length == 0)
            {
                return;
            }

            var drafts = dialog.FileNames
                .Where(filePath => !string.IsNullOrWhiteSpace(filePath))
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .Select(filePath => new ChatAttachmentSendDraft
                {
                    FilePath = filePath
                })
                .ToList();

            await SendConversationAttachmentDraftsAsync(conv, inputBox, drafts);
        }

        private async Task HandleConversationMediaSelectionAsync(Conversation conv, TextBox? inputBox, string title, string filter)
        {
            var dialog = new OpenFileDialog
            {
                Multiselect = true,
                Title = title,
                Filter = filter
            };

            if (dialog.ShowDialog() != true || dialog.FileNames.Length == 0)
            {
                return;
            }

            var selectedPaths = dialog.FileNames
                .Where(filePath => !string.IsNullOrWhiteSpace(filePath))
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();
            if (selectedPaths.Count == 0)
            {
                return;
            }

            var imagePaths = selectedPaths
                .Where(filePath => string.Equals(ResolveConversationAttachmentMessageType(filePath), "image", StringComparison.OrdinalIgnoreCase))
                .ToList();
            var remainingPaths = selectedPaths
                .Where(filePath => !imagePaths.Contains(filePath, StringComparer.OrdinalIgnoreCase))
                .ToList();

            var draftsToSend = new List<ChatAttachmentSendDraft>();

            if (imagePaths.Count > 0)
            {
                var imageDrafts = imagePaths
                    .Select(CreateConversationImageComposerDraft)
                    .Where(draft => draft != null)
                    .Cast<ChatImageComposerDraft>()
                    .ToList();

                if (imageDrafts.Count > 0)
                {
                    var composerResult = ShowConversationImageComposerDialog(imageDrafts);
                    if (composerResult.Confirmed && composerResult.Drafts.Count > 0)
                    {
                        var mediaGroupId = composerResult.Drafts.Count > 1
                            ? Guid.NewGuid().ToString("N")
                            : string.Empty;

                        for (var index = 0; index < composerResult.Drafts.Count; index++)
                        {
                            var draft = composerResult.Drafts[index];
                            draftsToSend.Add(new ChatAttachmentSendDraft
                            {
                                FilePath = draft.WorkingFilePath,
                                Caption = index == 0 ? composerResult.Caption : string.Empty,
                                PreviewDataUri = draft.PreviewDataUri,
                                MediaGroupId = mediaGroupId,
                                MediaGroupIndex = string.IsNullOrWhiteSpace(mediaGroupId) ? 0 : index,
                                MediaGroupCount = string.IsNullOrWhiteSpace(mediaGroupId) ? 0 : composerResult.Drafts.Count
                            });
                        }
                    }
                }
                else
                {
                    ShowStyledAlertDialog(
                        "CHAT",
                        "Imagens indisponiveis",
                        "As imagens selecionadas nao puderam ser preparadas para o composer agora.",
                        "Fechar",
                        new SolidColorBrush(Color.FromRgb(234, 88, 12)));
                }
            }

            draftsToSend.AddRange(remainingPaths.Select(filePath => new ChatAttachmentSendDraft
            {
                FilePath = filePath
            }));

            if (draftsToSend.Count == 0)
            {
                return;
            }

            await SendConversationAttachmentDraftsAsync(conv, inputBox, draftsToSend);
        }

        private async Task<bool> SendConversationAttachmentDraftsAsync(Conversation conv, TextBox? inputBox, IReadOnlyList<ChatAttachmentSendDraft> drafts)
        {
            var normalizedDrafts = (drafts ?? Array.Empty<ChatAttachmentSendDraft>())
                .Where(draft => draft != null && !string.IsNullOrWhiteSpace(draft.FilePath))
                .ToList();
            if (normalizedDrafts.Count == 0)
            {
                return false;
            }

            var sentMessages = new List<ChatMessage>();
            var failedFiles = new List<string>();
            ChatService? chatService = !string.IsNullOrWhiteSpace(_idToken)
                ? new ChatService(_idToken, _currentProfile?.UserId ?? string.Empty)
                : null;

            foreach (var draft in normalizedDrafts)
            {
                try
                {
                    if (!File.Exists(draft.FilePath))
                    {
                        failedFiles.Add($"{IOPath.GetFileName(draft.FilePath)} (arquivo nao encontrado)");
                        continue;
                    }

                    var localMessage = CreateLocalAttachmentMessage(
                        draft.FilePath,
                        draft.Caption,
                        draft.PreviewDataUri,
                        draft.MediaGroupId,
                        draft.MediaGroupIndex,
                        draft.MediaGroupCount);
                    ChatMessage messageToAppend = localMessage;

                    if (chatService != null)
                    {
                        var sendResult = await chatService.SendAttachmentMessageAsync(
                            conv.ContactId,
                            conv.ContactName,
                            localMessage.SenderName,
                            draft.FilePath,
                            caption: draft.Caption,
                            attachmentPreviewDataUri: draft.PreviewDataUri,
                            mediaGroupId: draft.MediaGroupId,
                            mediaGroupIndex: draft.MediaGroupIndex,
                            mediaGroupCount: draft.MediaGroupCount);

                        if (!sendResult.Success)
                        {
                            failedFiles.Add($"{IOPath.GetFileName(draft.FilePath)} ({sendResult.ErrorMessage})");
                            continue;
                        }

                        messageToAppend = NormalizeChatMessageForUi(sendResult.Message ?? localMessage);
                        if (string.IsNullOrWhiteSpace(messageToAppend.AttachmentLocalPath))
                        {
                            messageToAppend.AttachmentLocalPath = localMessage.AttachmentLocalPath;
                        }
                    }

                    sentMessages.Add(messageToAppend);
                }
                catch (Exception ex)
                {
                    DebugHelper.WriteLine($"[ChatAttachment] Falha ao enviar {draft.FilePath}: {ex.Message}");
                    failedFiles.Add($"{IOPath.GetFileName(draft.FilePath)} ({ex.Message})");
                }
            }

            if (sentMessages.Count > 0)
            {
                AppendMessagesToConversation(conv, sentMessages);
                inputBox?.Focus();
            }

            if (failedFiles.Count == 0)
            {
                return sentMessages.Count > 0;
            }

            var failureSummary = string.Join(Environment.NewLine, failedFiles.Take(4));
            if (failedFiles.Count > 4)
            {
                failureSummary += $"{Environment.NewLine}... e mais {failedFiles.Count - 4} arquivo(s).";
            }

            ShowStyledAlertDialog(
                "CHAT",
                sentMessages.Count > 0 ? "Envio parcial" : "Falha ao enviar anexo",
                sentMessages.Count > 0
                    ? $"Alguns anexos nao puderam ser enviados:{Environment.NewLine}{Environment.NewLine}{failureSummary}"
                    : $"Nenhum anexo foi enviado.{Environment.NewLine}{Environment.NewLine}{failureSummary}",
                "Fechar",
                new SolidColorBrush(Color.FromRgb(234, 88, 12)));

            return sentMessages.Count > 0;
        }

        private Task RecordConversationAudioAsync(Conversation conv, TextBox? inputBox)
        {
            var accentBrush = new SolidColorBrush(Color.FromRgb(20, 184, 166));
            var dialog = CreateStyledDialogWindow("Gravar audio", 720, 560, 500);
            var captionBox = new TextBox
            {
                MinHeight = 96,
                AcceptsReturn = true,
                TextWrapping = TextWrapping.Wrap,
                VerticalScrollBarVisibility = ScrollBarVisibility.Auto
            };
            ApplyDialogInputStyle(captionBox);

            var statusText = new TextBlock
            {
                Text = "Toque em iniciar para gravar pelo microfone do app.",
                FontSize = 12,
                Foreground = GetThemeBrush("SecondaryTextBrush"),
                TextWrapping = TextWrapping.Wrap,
                LineHeight = 20
            };
            var timerText = new TextBlock
            {
                Text = "00:00",
                FontSize = 32,
                FontWeight = FontWeights.ExtraBold,
                Foreground = GetThemeBrush("PrimaryTextBrush")
            };

            var startButton = CreateDialogActionButton("Iniciar gravação", accentBrush, Brushes.White, Brushes.Transparent, 160);
            var stopButton = CreateDialogActionButton("Parar", Brushes.Transparent, GetThemeBrush("PrimaryTextBrush"), GetThemeBrush("CardBorderBrush"), 120);
            var retryButton = CreateDialogActionButton("Gravar de novo", Brushes.Transparent, GetThemeBrush("PrimaryTextBrush"), GetThemeBrush("CardBorderBrush"), 150);
            var cancelButton = CreateDialogActionButton("Cancelar", Brushes.Transparent, GetThemeBrush("PrimaryTextBrush"), GetThemeBrush("CardBorderBrush"), 118);
            var sendButton = CreateDialogActionButton("Enviar audio", accentBrush, Brushes.White, Brushes.Transparent, 138);

            stopButton.IsEnabled = false;
            retryButton.IsEnabled = false;
            sendButton.IsEnabled = false;

            var root = new Grid();
            root.RowDefinitions.Add(new RowDefinition { Height = GridLength.Auto });
            root.RowDefinitions.Add(new RowDefinition { Height = new GridLength(1, GridUnitType.Star) });
            root.RowDefinitions.Add(new RowDefinition { Height = GridLength.Auto });

            root.Children.Add(CreateDialogHeader(
                "CHAT",
                "Gravação interna de áudio",
                "O áudio agora é capturado dentro do aplicativo. Grave, revise a legenda e só envie quando estiver pronto.",
                accentBrush));

            var body = new StackPanel();
            body.Children.Add(CreateDialogSectionCard(
                "Status da gravação",
                "O cronômetro corre só enquanto o microfone estiver ativo.",
                accentBrush,
                new StackPanel
                {
                    Children =
                    {
                        timerText,
                        new Border
                        {
                            Margin = new Thickness(0, 10, 0, 0),
                            Child = statusText
                        }
                    }
                }));

            var captionContent = new StackPanel();
            captionContent.Children.Add(CreateDialogFieldLabel("Legenda opcional"));
            captionContent.Children.Add(new Border
            {
                Margin = new Thickness(0, 8, 0, 0),
                Child = captionBox
            });
            captionContent.Children.Add(CreateDialogHintCard(
                "Use a legenda para contextualizar a gravação antes do envio. O arquivo só sobe quando você clicar em enviar.",
                accentBrush));

            body.Children.Add(CreateDialogSectionCard(
                "Legenda e envio",
                "A mesma lógica do composer vale aqui: grave, confira e só então confirme o envio.",
                accentBrush,
                captionContent,
                new Thickness(0, 0, 0, 0)));

            var scrollViewer = new ScrollViewer
            {
                VerticalScrollBarVisibility = ScrollBarVisibility.Auto,
                Content = body
            };
            Grid.SetRow(scrollViewer, 1);
            root.Children.Add(scrollViewer);

            var footer = new Border
            {
                Padding = new Thickness(0, 18, 0, 0),
                BorderBrush = GetThemeBrush("CardBorderBrush"),
                BorderThickness = new Thickness(0, 1, 0, 0)
            };
            var footerActions = new WrapPanel { HorizontalAlignment = HorizontalAlignment.Right };
            footerActions.Children.Add(startButton);
            footerActions.Children.Add(stopButton);
            footerActions.Children.Add(retryButton);
            footerActions.Children.Add(cancelButton);
            footerActions.Children.Add(sendButton);
            footer.Child = footerActions;
            Grid.SetRow(footer, 2);
            root.Children.Add(footer);

            dialog.Content = CreateStyledDialogShell(root);

            ChatMicrophoneRecorder? recorder = null;
            var recordingStartedAt = DateTime.MinValue;
            var recordedFilePath = string.Empty;
            var wasSent = false;
            var timer = new DispatcherTimer { Interval = TimeSpan.FromSeconds(1) };
            timer.Tick += (_, __) =>
            {
                if (recordingStartedAt == DateTime.MinValue)
                {
                    timerText.Text = "00:00";
                    return;
                }

                timerText.Text = FormatConversationAudioDuration(DateTime.Now - recordingStartedAt);
            };

            void ResetRecordingState(bool allowRestart)
            {
                timer.Stop();
                timerText.Text = "00:00";
                recordingStartedAt = DateTime.MinValue;
                startButton.IsEnabled = allowRestart;
                stopButton.IsEnabled = false;
                retryButton.IsEnabled = !string.IsNullOrWhiteSpace(recordedFilePath) || !allowRestart;
                sendButton.IsEnabled = !string.IsNullOrWhiteSpace(recordedFilePath) && File.Exists(recordedFilePath);
            }

            void ClearPendingRecording()
            {
                try
                {
                    recorder?.Cancel();
                }
                catch (Exception ex)
                {
                    DebugHelper.WriteLine($"[ChatAudio] Falha ao cancelar gravação: {ex.Message}");
                }

                recorder?.Dispose();
                recorder = null;

                if (!wasSent && !string.IsNullOrWhiteSpace(recordedFilePath) && File.Exists(recordedFilePath))
                {
                    try
                    {
                        File.Delete(recordedFilePath);
                    }
                    catch (Exception ex)
                    {
                        DebugHelper.WriteLine($"[ChatAudio] Falha ao limpar áudio temporário: {ex.Message}");
                    }
                }

                recordedFilePath = string.Empty;
            }

            startButton.Click += (_, __) =>
            {
                try
                {
                    ClearPendingRecording();
                    recordedFilePath = CreateConversationAudioRecordingPath(conv);
                    recorder = new ChatMicrophoneRecorder(recordedFilePath);
                    recorder.Start();
                    recordingStartedAt = DateTime.Now;
                    statusText.Text = "Gravando pelo microfone do aplicativo. Clique em parar quando terminar.";
                    timerText.Text = "00:00";
                    timer.Start();
                    startButton.IsEnabled = false;
                    stopButton.IsEnabled = true;
                    retryButton.IsEnabled = false;
                    sendButton.IsEnabled = false;
                }
                catch (Exception ex)
                {
                    ClearPendingRecording();
                    statusText.Text = "Não foi possível iniciar a gravação. Verifique o microfone e tente novamente.";
                    ShowStyledAlertDialog(
                        "CHAT",
                        "Microfone indisponível",
                        $"O aplicativo não conseguiu acessar o microfone agora.\n\n{ex.Message}",
                        "Fechar",
                        new SolidColorBrush(Color.FromRgb(220, 38, 38)));
                    ResetRecordingState(allowRestart: true);
                }
            };

            stopButton.Click += (_, __) =>
            {
                try
                {
                    recorder?.StopAndSave();
                    timer.Stop();
                    timerText.Text = FormatConversationAudioDuration(DateTime.Now - recordingStartedAt);
                    statusText.Text = "Áudio pronto para envio. Revise a legenda e confirme quando quiser publicar no chat.";
                    startButton.IsEnabled = false;
                    stopButton.IsEnabled = false;
                    retryButton.IsEnabled = true;
                    sendButton.IsEnabled = !string.IsNullOrWhiteSpace(recordedFilePath) && File.Exists(recordedFilePath);
                }
                catch (Exception ex)
                {
                    statusText.Text = "A gravação falhou ao ser finalizada. Você pode tentar novamente.";
                    ShowStyledAlertDialog(
                        "CHAT",
                        "Falha ao finalizar áudio",
                        $"O áudio não pôde ser salvo agora.\n\n{ex.Message}",
                        "Fechar",
                        new SolidColorBrush(Color.FromRgb(220, 38, 38)));
                    ClearPendingRecording();
                    ResetRecordingState(allowRestart: true);
                }
            };

            retryButton.Click += (_, __) =>
            {
                ClearPendingRecording();
                statusText.Text = "Gravação descartada. Inicie outra captura quando quiser.";
                ResetRecordingState(allowRestart: true);
            };

            cancelButton.Click += (_, __) => dialog.Close();
            sendButton.Click += async (_, __) =>
            {
                if (string.IsNullOrWhiteSpace(recordedFilePath) || !File.Exists(recordedFilePath))
                {
                    statusText.Text = "Nenhum áudio pronto para envio. Grave novamente para continuar.";
                    sendButton.IsEnabled = false;
                    return;
                }

                startButton.IsEnabled = false;
                stopButton.IsEnabled = false;
                retryButton.IsEnabled = false;
                sendButton.IsEnabled = false;
                cancelButton.IsEnabled = false;
                statusText.Text = "Enviando áudio para o chat...";

                var sent = await SendConversationAttachmentDraftsAsync(
                    conv,
                    inputBox,
                    new[]
                    {
                        new ChatAttachmentSendDraft
                        {
                            FilePath = recordedFilePath,
                            Caption = captionBox.Text?.Trim() ?? string.Empty
                        }
                    });

                if (sent)
                {
                    wasSent = true;
                    dialog.DialogResult = true;
                    dialog.Close();
                    return;
                }

                cancelButton.IsEnabled = true;
                retryButton.IsEnabled = true;
                sendButton.IsEnabled = true;
                statusText.Text = "O envio falhou. Você pode tentar de novo ou descartar esta gravação.";
            };

            dialog.Closed += (_, __) =>
            {
                timer.Stop();
                ClearPendingRecording();
            };

            dialog.ShowDialog();
            return Task.CompletedTask;
        }

        private ChatImageComposerDraft? CreateConversationImageComposerDraft(string filePath)
        {
            if (string.IsNullOrWhiteSpace(filePath) || !File.Exists(filePath))
            {
                return null;
            }

            var imageDataUri = TryCreateCompressedImageDataUri(filePath, 1480, 86) ?? string.Empty;
            var previewDataUri = TryCreateCompressedImageDataUri(filePath, 480, 74) ?? imageDataUri;
            if (string.IsNullOrWhiteSpace(imageDataUri) && string.IsNullOrWhiteSpace(previewDataUri))
            {
                return null;
            }

            return new ChatImageComposerDraft
            {
                OriginalFilePath = filePath,
                WorkingFilePath = filePath,
                DisplayFileName = IOPath.GetFileName(filePath),
                ImageDataUri = string.IsNullOrWhiteSpace(imageDataUri) ? previewDataUri : imageDataUri,
                PreviewDataUri = string.IsNullOrWhiteSpace(previewDataUri) ? imageDataUri : previewDataUri
            };
        }

