                ? new SolidColorBrush(Color.FromArgb(68, 255, 255, 255))
                : _appDarkModeEnabled
                    ? new SolidColorBrush(Color.FromRgb(71, 85, 105))
                    : new SolidColorBrush(Color.FromRgb(226, 232, 240));
            var secondaryTextBrush = msg.IsOwn
                ? new SolidColorBrush(Color.FromArgb(214, 255, 255, 255))
                : GetThemeBrush("SecondaryTextBrush");

            var border = new Border
            {
                Margin = new Thickness(0, ShouldShowConversationMessageText(msg) ? 8 : 0, 0, 0),
                Padding = new Thickness(12),
                CornerRadius = new CornerRadius(14),
                Background = cardBackground,
                BorderBrush = cardBorder,
                BorderThickness = new Thickness(1),
                Cursor = Cursors.Hand,
                ToolTip = "Abrir link"
            };

            var previewContent = new StackPanel { Orientation = Orientation.Vertical };
            previewContent.Children.Add(new TextBlock
            {
                Text = string.IsNullOrWhiteSpace(msg.LinkDisplayHost) ? "Link" : msg.LinkDisplayHost,
                FontSize = 11,
                FontWeight = FontWeights.SemiBold,
                Foreground = secondaryTextBrush
            });
            previewContent.Children.Add(new TextBlock
            {
                Text = string.IsNullOrWhiteSpace(msg.LinkTitle) ? msg.LinkUrl : msg.LinkTitle,
                Margin = new Thickness(0, 4, 0, 0),
                FontSize = 13,
                FontWeight = FontWeights.SemiBold,
                Foreground = primaryTextBrush,
                TextWrapping = TextWrapping.Wrap
            });

            var description = string.IsNullOrWhiteSpace(msg.LinkDescription)
                ? msg.LinkUrl
                : msg.LinkDescription;
            if (!string.IsNullOrWhiteSpace(description))
            {
                previewContent.Children.Add(new TextBlock
                {
                    Text = description,
                    Margin = new Thickness(0, 6, 0, 0),
                    FontSize = 11,
                    Foreground = secondaryTextBrush,
                    TextWrapping = TextWrapping.Wrap
                });
            }

            border.Child = previewContent;
            border.MouseLeftButtonUp += (_, __) => OpenConversationExternalLink(msg.LinkUrl);
            return border;
        }

        private ImageSource? TryCreateConversationAttachmentPreviewSource(ChatMessage msg)
        {
            return TryCreateConversationAttachmentDisplaySource(msg, preferLocalFile: false, decodePixelWidth: 420);
        }

        private ImageSource? TryCreateConversationAttachmentDisplaySource(ChatMessage msg, bool preferLocalFile, int decodePixelWidth = 0)
        {
            if (msg == null || !msg.IsImageAttachment)
            {
                return null;
            }

            if (preferLocalFile && !string.IsNullOrWhiteSpace(msg.AttachmentLocalPath) && File.Exists(msg.AttachmentLocalPath))
            {
                var localSource = TryCreateDecodedBitmapImage(msg.AttachmentLocalPath, decodePixelWidth);
                if (localSource != null)
                {
                    return localSource;
                }
            }

            var previewSource = TryCreateImageSourceFromDataUri(msg.AttachmentPreviewDataUri);
            if (previewSource != null)
            {
                return previewSource;
            }

            if (!preferLocalFile && !string.IsNullOrWhiteSpace(msg.AttachmentLocalPath) && File.Exists(msg.AttachmentLocalPath))
            {
                return TryCreateDecodedBitmapImage(msg.AttachmentLocalPath, decodePixelWidth);
            }

            return null;
        }

        private BitmapImage? TryCreateDecodedBitmapImage(string filePath, int decodePixelWidth = 0)
        {
            if (string.IsNullOrWhiteSpace(filePath) || !File.Exists(filePath))
            {
                return null;
            }

            try
            {
                var bitmap = new BitmapImage();
                bitmap.BeginInit();
                bitmap.CacheOption = BitmapCacheOption.OnLoad;
                bitmap.CreateOptions = BitmapCreateOptions.PreservePixelFormat;
                if (decodePixelWidth > 0)
                {
                    bitmap.DecodePixelWidth = decodePixelWidth;
                }

                bitmap.UriSource = new Uri(filePath, UriKind.Absolute);
                bitmap.EndInit();
                if (bitmap.CanFreeze)
                {
                    bitmap.Freeze();
                }

                return bitmap;
            }
            catch (Exception ex)
            {
                DebugHelper.WriteLine($"[ChatAttachmentPreview] Falha ao montar preview de {filePath}: {ex.Message}");
                return null;
            }
        }

        private async Task OpenConversationAttachmentAsync(ChatMessage msg)
        {
            var localPath = msg.AttachmentLocalPath;
            if (string.IsNullOrWhiteSpace(localPath) || !File.Exists(localPath))
            {
                if (string.IsNullOrWhiteSpace(_idToken))
                {
                    ShowStyledAlertDialog(
                        "CHAT",
                        "Anexo indisponivel",
                        "Este dispositivo nao possui uma copia local do anexo e a sessao atual nao permite baixar do Firebase.",
                        "Fechar",
                        new SolidColorBrush(Color.FromRgb(220, 38, 38)));
                    return;
                }

                var chatService = new ChatService(_idToken, _currentProfile?.UserId ?? string.Empty);
                var downloadResult = await chatService.EnsureAttachmentLocalCopyAsync(msg);
                if (!downloadResult.Success || string.IsNullOrWhiteSpace(downloadResult.LocalPath) || !File.Exists(downloadResult.LocalPath))
                {
                    ShowStyledAlertDialog(
                        "CHAT",
                        "Nao foi possivel baixar",
                        $"O anexo nao pode ser baixado agora.\n\n{downloadResult.ErrorMessage}",
                        "Fechar",
                        new SolidColorBrush(Color.FromRgb(220, 38, 38)));
                    return;
                }

                localPath = downloadResult.LocalPath;
                msg.AttachmentLocalPath = localPath;
                RefreshChatsUI();
            }

            try
            {
                Process.Start(new ProcessStartInfo
                {
                    FileName = localPath,
                    UseShellExecute = true
                });
            }
            catch (Exception ex)
            {
                DebugHelper.WriteLine($"[ChatAttachmentOpen] Falha ao abrir {localPath}: {ex.Message}");
                ShowStyledAlertDialog(
                    "CHAT",
                    "Nao foi possivel abrir",
                    "O sistema nao conseguiu abrir este anexo no app padrao agora.",
                    "Fechar",
                    new SolidColorBrush(Color.FromRgb(234, 88, 12)));
            }
        }

        private void OpenConversationExternalLink(string? linkUrl)
        {
            var normalizedUrl = (linkUrl ?? string.Empty).Trim();
            if (string.IsNullOrWhiteSpace(normalizedUrl))
            {
                return;
            }

            try
            {
                Process.Start(new ProcessStartInfo
                {
                    FileName = normalizedUrl,
                    UseShellExecute = true
                });
            }
            catch (Exception ex)
            {
                DebugHelper.WriteLine($"[ChatLink] Falha ao abrir {normalizedUrl}: {ex.Message}");
                ShowStyledAlertDialog(
                    "CHAT",
                    "Link indisponivel",
                    "Nao foi possivel abrir o link desta mensagem agora.",
                    "Fechar",
                    new SolidColorBrush(Color.FromRgb(220, 38, 38)));
            }
        }

        private static string FormatConversationAttachmentSize(long sizeBytes)
        {
            if (sizeBytes <= 0)
            {
                return "Tamanho nao informado";
            }

            string[] units = { "B", "KB", "MB", "GB" };
            var value = (double)sizeBytes;
            var unitIndex = 0;
            while (value >= 1024 && unitIndex < units.Length - 1)
            {
                value /= 1024;
                unitIndex++;
            }

            return $"{value:0.#} {units[unitIndex]}";
        }

        private ImageSource? TryCreateStickerImageSource(string? assetFileName)
        {
            if (string.IsNullOrWhiteSpace(assetFileName))
            {
                return null;
            }

            if (_stickerImageCache.TryGetValue(assetFileName, out var cachedSource))
            {
                return cachedSource;
            }

            static string? ResolveStickerPath(string fileName)
            {
                var baseDirectory = AppDomain.CurrentDomain.BaseDirectory;
                var candidateDirectories = new[]
                {
                    System.IO.Path.Combine(baseDirectory, "img", "emojiobsseract"),
                    System.IO.Path.Combine(baseDirectory, "..", "..", "..", "img", "emojiobsseract")
                };

                foreach (var directory in candidateDirectories)
                {
                    if (!Directory.Exists(directory))
                    {
                        continue;
                    }

                    var directPath = System.IO.Path.Combine(directory, fileName);
                    if (File.Exists(directPath))
                    {
                        return System.IO.Path.GetFullPath(directPath);
                    }

                    foreach (var candidatePath in Directory.GetFiles(directory, "*.png"))
                    {
                        if (string.Equals(System.IO.Path.GetFileName(candidatePath), fileName, StringComparison.OrdinalIgnoreCase))
                        {
                            return System.IO.Path.GetFullPath(candidatePath);
                        }
                    }
                }

                return null;
            }

            try
            {
                var source = CreateFrozenBitmapImage(new Uri($"pack://application:,,,/img/emojiobsseract/{assetFileName}", UriKind.Absolute));
                _stickerImageCache[assetFileName] = source;
                return source;
            }
            catch
            {
                try
                {
                    var stickerPath = ResolveStickerPath(assetFileName);
                    if (string.IsNullOrWhiteSpace(stickerPath))
                    {
                        DebugHelper.WriteLine($"[Sticker] Arquivo não encontrado: {assetFileName}");
                        return null;
                    }

                    var source = CreateFrozenBitmapImage(new Uri(stickerPath, UriKind.Absolute));
                    _stickerImageCache[assetFileName] = source;
                    return source;
                }
                catch (Exception fallbackEx)
                {
                    DebugHelper.WriteLine($"[Sticker] Falha no fallback de arquivo {assetFileName}: {fallbackEx.Message}");
                    return null;
                }
            }
        }

        private string GetStickerPreviewText(string? assetFileName)
        {
            return $"Figurinha • {GetStickerDisplayName(assetFileName)}";
