        private string GetStickerDisplayName(string? assetFileName)
        {
            return (assetFileName ?? string.Empty).ToLowerInvariant() switch
            {
                "chao_0.png" => "Feliz",
                "chao_1.png" => "Triste",
                "chao_2.png" => "Irritado",
                "chao_3.png" => "Annya Smile",
                "chao_4.png" => "Pikachu Shock",
                "chao_5.png" => "Love Chao",
                "chao_6.png" => "Close-up Face",
                _ => "Figurinha"
            };
        }

        private async Task LoadActiveConversationsAsync()
        {
            try
            {
                DebugHelper.WriteLine("[LoadActiveConversations] Carregando conversas ativas do Firebase");

                var chatService = new ChatService(_idToken, _currentProfile?.UserId ?? "");
                var conversations = await chatService.LoadConversationsAsync();
                await EnrichConversationAvatarsAsync(conversations);
                NormalizeChatConversations(conversations);

                _conversations = conversations;

                if (_selectedConversation != null)
                {
                    _selectedConversation = _conversations.FirstOrDefault(c => c.ContactId == _selectedConversation.ContactId);
                }
                else
                {
                    _selectedConversation = _conversations.FirstOrDefault(c => c.IsSelfConversation)
                        ?? _conversations.FirstOrDefault();
                }

                UpdateChatsBadge();
                QueueChatsUiRefresh();
                DebugHelper.WriteLine($"[LoadActiveConversations] {conversations.Count} conversas carregadas");
            }
            catch (Exception ex)
            {
                DebugHelper.WriteLine($"[LoadActiveConversations ERROR] {ex.Message}");
            }
        }

        /// <summary>
        /// Carrega as equipes do banco de dados Firebase
        /// </summary>
        private async Task LoadTeamsFromDatabaseAsync(bool force = false)
        {
            if (_teamLoadInFlight)
            {
                return;
            }

            if (!force &&
                _dirtyTeamPersistenceState.Count == 0 &&
                DateTime.UtcNow - _lastTeamLoadAt < TimeSpan.FromSeconds(75))
            {
                DebugHelper.WriteLine("[LoadTeamsFromDatabase] Reuso do cache temporário de equipes; refresh remoto adiado.");
                return;
            }

            _teamLoadInFlight = true;
            try
            {
                DebugHelper.WriteLine("[LoadTeamsFromDatabase] Carregando equipes do Firebase");

                if (_teamService == null)
                {
                    DebugHelper.WriteLine("[LoadTeamsFromDatabase] TeamService não inicializado");
                    return;
                }

                var teams = await _teamService.LoadTeamsAsync();
                if (teams.Count == 0 && CurrentViewerCanUseProfessorDiscovery())
                {
                    DebugHelper.WriteLine("[LoadTeamsFromDatabase] Nenhuma equipe vinculada diretamente. Carregando equipes visíveis para perfil docente...");
                    teams = await _teamService.LoadAllVisibleTeamsAsync();
                }

                await EnrichTeamMembersAvatarsAsync(teams);

                var mergedTeams = MergeRemoteTeamsWithDirtyLocalState(teams);

                _teamWorkspaces.Clear();
                _userAcademicPortfolioCache.Clear();
                foreach (var team in mergedTeams)
                {
                    _teamWorkspaces.Add(team);
                }

                UpdateTeamsViewState();
                RenderTeamsList();
                if (_activeTeamWorkspace != null)
                {
                    _activeTeamWorkspace = _teamWorkspaces.FirstOrDefault(team => string.Equals(team.TeamId, _activeTeamWorkspace.TeamId, StringComparison.OrdinalIgnoreCase));
                    RenderTeamWorkspace();
                }

                RenderProfessorDashboard();
                RenderCalendarAgenda();
                _lastTeamLoadAt = DateTime.UtcNow;

                DebugHelper.WriteLine($"[LoadTeamsFromDatabase] {mergedTeams.Count} equipes carregadas do banco de dados ({_dirtyTeamPersistenceState.Count} protegida(s) por estado local pendente).");
            }
            catch (Exception ex)
            {
                DebugHelper.WriteLine($"[LoadTeamsFromDatabase ERROR] {ex.Message}");
                DebugHelper.WriteLine($"[LoadTeamsFromDatabase ERROR] Stack: {ex.StackTrace}");
            }
            finally
            {
                _teamLoadInFlight = false;
            }
        }

        private async Task LoadTeachingClassesFromDatabaseAsync(bool force = false)
        {
            if (_teachingClassLoadInFlight)
            {
                return;
            }

            if (!force && DateTime.UtcNow - _lastTeachingClassLoadAt < TimeSpan.FromSeconds(75))
            {
                DebugHelper.WriteLine("[LoadTeachingClasses] Reuso do cache temporário de turmas docentes; refresh remoto adiado.");
                return;
            }

            if (_teachingClassService == null)
            {
                return;
            }

            _teachingClassLoadInFlight = true;
            try
            {
                var localFeedState = _teachingClasses
                    .Where(item => item != null && !string.IsNullOrWhiteSpace(item.ClassId))
                    .ToDictionary(item => item.ClassId, item => item, StringComparer.OrdinalIgnoreCase);
                var classes = await _teachingClassService.LoadClassesAsync();
                _teachingClasses.Clear();
                _teachingClasses.AddRange(classes
                    .OfType<TeachingClassInfo>()
                    .Select(item =>
                    {
                        if (localFeedState.TryGetValue(item.ClassId, out var existing))
                        {
                            item.HomePosts = existing.HomePosts ?? new List<TeachingClassHomePostInfo>();
                            item.HomeFeedReady = existing.HomeFeedReady;
                            item.HomeFeedLoadedAt = existing.HomeFeedLoadedAt;
                        }

                        return item;
                    })
                    .OrderBy(item => item.Course)
                    .ThenBy(item => item.ClassName));

                _lastTeachingClassLoadAt = DateTime.UtcNow;
                SynchronizeTeachingClassWorkspaceState();
                UpdateTeamsViewState();
                RenderTeamsList();
                RenderProfessorDashboard();
                DebugHelper.WriteLine($"[LoadTeachingClasses] {_teachingClasses.Count} turma(s) docente(s) carregada(s).");
            }
            catch (Exception ex)
            {
                DebugHelper.WriteLine($"[LoadTeachingClasses ERROR] {ex.Message}");
            }
            finally
            {
                _teachingClassLoadInFlight = false;
            }
        }

        private void TrackTeachingClassLocally(TeachingClassInfo teachingClass)
        {
            if (teachingClass == null)
            {
                return;
            }

            var existingIndex = _teachingClasses.FindIndex(item =>
                string.Equals(item.ClassId, teachingClass.ClassId, StringComparison.OrdinalIgnoreCase));

            if (existingIndex >= 0)
            {
                _teachingClasses[existingIndex] = teachingClass;
            }
            else
            {
                _teachingClasses.Add(teachingClass);
            }

            _teachingClasses.Sort((left, right) =>
            {
                var courseComparison = string.Compare(left.Course, right.Course, StringComparison.OrdinalIgnoreCase);
                return courseComparison != 0
                    ? courseComparison
                    : string.Compare(left.ClassName, right.ClassName, StringComparison.OrdinalIgnoreCase);
            });

            if (_activeTeachingClass != null && string.Equals(_activeTeachingClass.ClassId, teachingClass.ClassId, StringComparison.OrdinalIgnoreCase))
            {
                _activeTeachingClass = teachingClass;
            }

            SynchronizeTeachingClassWorkspaceState();
            UpdateTeamsViewState();
            RenderTeamsList();
            RenderProfessorDashboard();
        }

